-- Insert tours
INSERT INTO tours (title, description, price, duration, rating, reviews_count, image, location, country, category, tags, hotel, hotel_stars, included, not_included, is_hot, discount, max_people) VALUES
('Романтический Бали', 'Откройте для себя волшебство Бали: рисовые террасы Убуда, древние храмы Танах Лот, водопады Тегенунган и закаты на пляже Кута. Идеальный тур для пар и семей.', 1299, 10, 4.8, 124, 'https://images.unsplash.com/photo-1537996194471-e657df975ab4?w=800&q=80', 'Бали', 'Индонезия', 'Пляжный', ARRAY['пляж', 'культура', 'природа'], 'Ayana Resort', 5, ARRAY['перелет', 'трансфер', 'завтрак', 'экскурсии'], ARRAY['обед', 'ужин', 'личные расходы'], true, 15, 30),

('Париж — город любви', 'Погрузитесь в атмосферу Парижа: Эйфелева башня, Лувр, прогулки по Сене, квартал Монмартр и французская кухня. Романтика на каждом шагу.', 1599, 7, 4.9, 89, 'https://images.unsplash.com/photo-1502602898657-3e91760cbb34?w=800&q=80', 'Париж', 'Франция', 'Экскурсионный', ARRAY['экскурсии', 'культура', 'романтика'], 'Hotel Regina', 4, ARRAY['перелет', 'трансфер', 'завтрак'], ARRAY['обед', 'ужин', 'входные билеты'], true, 10, 25),

('Токио: традиции и технологии', 'Контрасты Токио: древние храмы Асакусы, неоновый Сибуя, храм Мэйдзи, рынок Цукидзи и традиционные сады. Уникальное погружение в японскую культуру.', 1899, 9, 4.7, 67, 'https://images.unsplash.com/photo-1540959733332-eab4deabeeaf?w=800&q=80', 'Токио', 'Япония', 'Экскурсионный', ARRAY['культура', 'технологии', 'еда'], 'Park Hyatt Tokyo', 5, ARRAY['перелет', 'трансфер', 'завтрак'], ARRAY['обед', 'ужин', 'входные билеты'], false, 0, 20),

('Роскошь Дубая', 'Дубай — город будущего: Бурдж-Халифа, Дубай-Молл, сафари в пустыне, искусственные острова Пальма и роскошные отели. Незабываемый отдых.', 2199, 6, 4.6, 156, 'https://images.unsplash.com/photo-1512453979798-5ea266f8880c?w=800&q=80', 'Дубай', 'ОАЭ', 'Пляжный', ARRAY['роскошь', 'шопинг', 'пустыня'], 'Atlantis The Palm', 5, ARRAY['перелет', 'трансфер', 'завтрак', 'экскурсии'], ARRAY['обед', 'ужин', 'личные расходы'], true, 20, 30),

('Мальдивы: рай на земле', 'Бирюзовая лагуна, белый песок, водные бунгало и подводный мир. Идеальное место для медового месяца и романтического отдыха.', 2599, 8, 4.9, 203, 'https://images.unsplash.com/photo-1514282401047-d79a71a590e8?w=800&q=80', 'Мале', 'Мальдивы', 'Пляжный', ARRAY['пляж', 'дайвинг', 'романтика'], 'Conrad Maldives', 5, ARRAY['перелет', 'трансфер', 'завтрак', 'ужин'], ARRAY['алкоголь', 'спа', 'водные виды спорта'], false, 0, 16),

('Нью-Йорк: город мечты', 'Таймс-сквер, Центральный парк, Статуя Свободы, Бруклинский мост и Бродвей. Почувствуйте пульс самого динамичного города мира.', 1799, 5, 4.5, 98, 'https://images.unsplash.com/photo-1496442226666-8d4d0e62e6e9?w=800&q=80', 'Нью-Йорк', 'США', 'Экскурсионный', ARRAY['город', 'культура', 'шопинг'], 'The Plaza', 5, ARRAY['перелет', 'трансфер', 'завтрак'], ARRAY['обед', 'ужин', 'входные билеты'], true, 12, 30),

('Санторини: белоснежные дома', 'Знаменитые белые дома с голубыми куполами, закаты в Ие, винодельни и древние руины Акротири. Самый романтичный остров Греции.', 1399, 7, 4.8, 76, 'https://images.unsplash.com/photo-1570077188670-e3a8d69ac5ff?w=800&q=80', 'Санторини', 'Греция', 'Пляжный', ARRAY['пляж', 'романтика', 'вино'], 'Canaves Oia', 5, ARRAY['перелет', 'трансфер', 'завтрак'], ARRAY['обед', 'ужин', 'входные билеты'], false, 0, 20),

('Швейцарские Альпы', 'Живописные Альпы: Церматт, Маттерхорн, Женевское озеро, поезд Glacier Express и шоколадные фабрики. Природа в её лучшем проявлении.', 2299, 8, 4.7, 54, 'https://images.unsplash.com/photo-1530122037265-a5f1f91d3b99?w=800&q=80', 'Цюрих', 'Швейцария', 'Горный', ARRAY['горы', 'природа', 'поезд'], 'Badrutt Palace', 5, ARRAY['перелет', 'трансфер', 'завтрак'], ARRAY['обед', 'ужин', 'проездной'], false, 0, 18)
ON CONFLICT DO NOTHING;

-- Insert blog posts
INSERT INTO blog_posts (title, excerpt, content, author, author_avatar, date, image, category, read_time, likes) VALUES
('10 советов для путешественников: как упаковать чемодан', 'Узнайте, как правильно упаковать чемодан, чтобы взять с собой всё необходимое и не переплачивать за багаж. Практические советы от опытных путешественников.', 'Полный текст статьи о том, как правильно упаковать чемодан для путешествия. Включает советы по выбору одежды, организации пространства, использованию packing cubes и многое другое.', 'Анна Петрова', 'https://ui-avatars.com/api/?name=Anna+Petrova&background=10b981&color=fff', '15 января 2024', 'https://images.unsplash.com/photo-1553531384-411a247ccd73?w=800&q=80', 'Советы', 8, 124),

('Бали: секретные пляжи, о которых мало кто знает', 'Откройте для себя скрытые уголки Бали — пляжи без толп туристов, где можно насладиться природой в полной тишине. Местные жемчужины острова богов.', 'Полное руководство по секретным пляжам Бали. Мы расскажем о пляжах Nyang Nyang, Green Bowl, Melasti и других скрытых локациях, где можно избежать туристических толп.', 'Максим Волков', 'https://ui-avatars.com/api/?name=Maxim+Volkov&background=047857&color=fff', '10 января 2024', 'https://images.unsplash.com/photo-1537996194471-e657df975ab4?w=800&q=80', 'Направления', 12, 89),

('Как путешествовать дешево: лайфхаки от бюджетных туристов', 'Путешествовать можно и нужно даже с ограниченным бюджетом. Узнайте проверенные способы экономии на перелетах, жилье, еде и развлечениях.', 'Подробное руководство по бюджетным путешествиям: как найти дешевые авиабилеты, забронировать хостел или каучсерфинг, готовить еду самостоятельно и пользоваться бесплатными достопримечательностями.', 'Елена Смирнова', 'https://ui-avatars.com/api/?name=Elena+Smirnova&background=059669&color=fff', '5 января 2024', 'https://images.unsplash.com/photo-1469854523086-cc02fe5d8800?w=800&q=80', 'Советы', 10, 156),

('Японская кухня: гастрономическое путешествие', 'Рамен, суши, тэмпура, вагю и многое другое. Погрузитесь в мир японской гастрономии и узнайте, где попробовать лучшие блюда в Токио, Киото и Осаке.', 'Гастрономический гид по Японии: от уличной еды до мишленовских ресторанов. Рецепты, истории и лучшие адреса для настоящих гурманов.', 'Дмитрий Козлов', 'https://ui-avatars.com/api/?name=Dmitry+Kozlov&background=065f46&color=fff', '1 января 2024', 'https://images.unsplash.com/photo-1580822184713-fc5400e7fe10?w=800&q=80', 'Еда', 15, 67),

('Европа за 2 недели: идеальный маршрут', 'Как увидеть лучшее из Европы за 14 дней: Париж, Амстердам, Берлин, Прага, Вена, Рим. Оптимальный маршрут с советами по транспорту и жилью.', 'Детальный маршрут по Европе: маршрут, стоимость, советы по транспорту, лучшие районы для проживания, must-see достопримечательности и скрытые жемчужины каждого города.', 'Ольга Новикова', 'https://ui-avatars.com/api/?name=Olga+Novikova&background=047857&color=fff', '28 декабря 2023', 'https://images.unsplash.com/photo-1499856871958-5b9627545d1a?w=800&q=80', 'Маршруты', 18, 203),

('Сафари в Африке: что нужно знать', 'Планируете сафари? Узнайте о лучших национальных парках, сезонах для наблюдения за животными, необходимых прививках и бюджете поездки.', 'Полное руководство по сафари в Африке: Кения, Танзания, ЮАР, Ботсвана. Лучшее время для посещения, что брать с собой, безопасность и этика наблюдения за дикой природой.', 'Иван Соколов', 'https://ui-avatars.com/api/?name=Ivan+Sokolov&background=10b981&color=fff', '20 декабря 2023', 'https://images.unsplash.com/photo-1516426122078-c23e76319801?w=800&q=80', 'Приключения', 14, 91)
ON CONFLICT DO NOTHING;

