-- Insert forum replies
INSERT INTO forum_replies (topic_id, author, author_avatar, content, date, likes) VALUES
((SELECT id FROM forum_topics WHERE title = 'Какой тур выбрать для первого путешествия?' LIMIT 1), 'Андрей С.', 'https://ui-avatars.com/api/?name=Andrey+S&background=059669&color=fff', 'Я бы рекомендовал начать с Европы — там всё понятно и безопасно. Париж или Рим — отличный выбор для первого раза!', '1 час назад', 5),
((SELECT id FROM forum_topics WHERE title = 'Какой тур выбрать для первого путешествия?' LIMIT 1), 'Виктория Н.', 'https://ui-avatars.com/api/?name=Viktoria+N&background=065f46&color=fff', 'Согласна с Андреем! Ещё можно рассмотреть Турцию или Египет — недорого и всё включено.', '45 минут назад', 3),
((SELECT id FROM forum_topics WHERE title = 'Бали в декабре: погода и рекомендации' LIMIT 1), 'Денис К.', 'https://ui-avatars.com/api/?name=Denis+K&background=10b981&color=fff', 'В декабре на Бали сезон дождей, но дожди обычно кратковременные. Берите зонт и не планируйте серфинг на западном побережье.', '3 часа назад', 7)
ON CONFLICT DO NOTHING;

-- Insert reviews
INSERT INTO reviews (tour_id, name, avatar, rating, text, date) VALUES
((SELECT id FROM tours WHERE title = 'Романтический Бали' LIMIT 1), 'Анна М.', 'https://ui-avatars.com/api/?name=Anna+M&background=10b981&color=fff', 5, 'Незабываемое путешествие! Отель просто шикарный, экскурсии были очень интересными. Обязательно вернусь!', '15 января 2024'),
((SELECT id FROM tours WHERE title = 'Романтический Бали' LIMIT 1), 'Павел Р.', 'https://ui-avatars.com/api/?name=Pavel+R&background=047857&color=fff', 4, 'Отличный тур, но немного утомительные переезды между локациями. Природа Бали потрясающая!', '10 января 2024'),
((SELECT id FROM tours WHERE title = 'Париж — город любви' LIMIT 1), 'София Л.', 'https://ui-avatars.com/api/?name=Sofia+L&background=059669&color=fff', 5, 'Париж превзошёл все ожидания! Гид был очень knowledgeable, а отель в центре города — просто мечта.', '12 января 2024')
ON CONFLICT DO NOTHING;
